(function () {
  function addStyle() { if (document.getElementById('scn-style')) return; var s = document.createElement('style'); s.id = 'scn-style'; s.textContent = '.scn-wrap{border:1px solid #e5e7eb;border-radius:12px;padding:16px;background:#fff;margin:14px 0}.scn-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(130px,1fr));gap:12px;align-items:end}.scn-grid label{display:flex;flex-direction:column;gap:5px}.scn-grid input{padding:8px;border:1px solid #cbd5e1;border-radius:8px}.scn-out{margin-top:12px;padding:12px;border-radius:8px;background:#f8f9fa;line-height:1.7}.scn-table{width:100%;border-collapse:collapse;margin-top:10px}.scn-table th,.scn-table td{border:1px solid #e5e7eb;padding:7px;text-align:center}.scn-result{padding:10px;border-left:4px solid #28a745;background:#d4edda;border-radius:8px}'; document.head.appendChild(s); }
  function comb(n, k) { if (k < 0 || k > n) return 0; var r = 1; for (var i = 1; i <= k; i++) r = r * (n - k + i) / i; return Math.round(r); }
  function fact(n) { var r = 1; for (var i = 2; i <= n; i++) r *= i; return r; }
  function stir(n, m) { var dp = Array(m + 1).fill(0); dp[0] = 1; for (var i = 1; i <= n; i++) for (var j = m; j >= 1; j--) dp[j] = j * dp[j] + dp[j - 1]; return dp[m]; }
  function mount(host) { if (!host || host.dataset.scnMounted) return; host.dataset.scnMounted = '1'; addStyle(); host.innerHTML = '<div class="scn-wrap"><h4>🎯 Đếm ánh xạ toàn ánh</h4><div class="scn-grid"><label>n: số phần tử miền nguồn <input data-n type="number" min="0" max="10" value="5"></label><label>m: số phần tử miền đích <input data-m type="number" min="0" max="8" value="3"></label><button type="button" data-run>Tính</button></div><div class="scn-out"></div></div>'; var out = host.querySelector('.scn-out'); function run() { var n = Math.max(0, parseInt(host.querySelector('[data-n]').value, 10) || 0), m = Math.max(0, parseInt(host.querySelector('[data-m]').value, 10) || 0), total = 0, rows = []; for (var k = 0; k <= m; k++) { var term = Math.pow(-1, k) * comb(m, k) * Math.pow(m - k, n); total += term; rows.push('<tr><td>' + k + '</td><td>' + (k % 2 ? '-' : '+') + ' C(' + m + ',' + k + ')·' + (m - k) + '^' + n + '</td><td>' + term + '</td></tr>'); } out.innerHTML = '<div class="scn-result">Surj(' + n + ',' + m + ') = Σ(-1)^k C(' + m + ',k)(' + m + '-k)^' + n + ' = <strong>' + total + '</strong></div><p>Dạng tương đương: m!·S(n,m) = ' + fact(m) + '·' + stir(n, m) + '.</p><p>Tổng mọi hàm: ' + m + '^' + n + ' = ' + Math.pow(m, n) + '. Sau đó trừ hàm bỏ sót ít nhất một giá trị đích, cộng lại phần bị trừ hai lần, ...</p><table class="scn-table"><tr><th>k bỏ sót</th><th>Hạng tử</th><th>Giá trị</th></tr>' + rows.join('') + '</table>'; } host.querySelector('[data-run]').addEventListener('click', run); run(); }
  document.addEventListener('DOMContentLoaded', function () { document.querySelectorAll('[data-demo="surjection-counter"]').forEach(mount); });
}());
